solution_code:
#include <stdio.h>

unsigned int shift_left(unsigned int val, int n) {
    return val << n;
}

unsigned int shift_right(unsigned int val, int n) {
    return val >> n;
}

unsigned int power_of_two(int n) {
    return 1 << n;
}

int main(void) {
    {
        printf("%d\n", (int)(shift_left(0x15, 1)));
        printf("%d\n", (int)(shift_left(0x15, 4)));
        printf("%d\n", (int)(shift_left(0x50, 1)));
        printf("%d\n", (int)(shift_left(2, 2)));
    }
    {
        printf("%d\n", (int)(shift_right(0x15, 1)));
        printf("%d\n", (int)(shift_right(0x15, 3)));
        printf("%d\n", (int)(shift_right(0xFF, 1)));
        printf("%d\n", (int)(shift_right(0x01, 2)));
    }
    {
        printf("%d\n", (int)(power_of_two(0)));
        printf("%d\n", (int)(power_of_two(3)));
        printf("%d\n", (int)(power_of_two(7)));
        printf("%d\n", (int)(power_of_two(8)));
    }
    return 0;
}

